code = """import pandas as pd, json
cases = pd.DataFrame(var_call_Or5DanJ7LWWLGDDyEzHQfTUc)
accounts = pd.DataFrame(var_call_eRWdGsk8VMIY4dtdBlbfMDm7)
accounts['Id_clean'] = accounts['Id'].str.lstrip('#')
merged = cases.merge(accounts, left_on='account_clean', right_on='Id_clean', how='left')
merged['createddate'] = pd.to_datetime(merged['createddate'])
merged['closeddate'] = pd.to_datetime(merged['closeddate'])
merged['closure_hours'] = (merged['closeddate'] - merged['createddate']).dt.total_seconds() / 3600.0

# Define past 6 quarters relative to 2022-10-26 (exclusive), i.e., Q2 2021 to Q3 2022
ref = pd.Timestamp('2022-10-26')
# Quarter index from ref: quarter = floor((year*4 + quarter-1))
q_index = (merged['createddate'].dt.year * 4 + (merged['createddate'].dt.quarter-1))
ref_q_index = (ref.year * 4 + (ref.quarter-1))
merged = merged[q_index >= ref_q_index - 5]

state_avg = merged.groupby('ShippingState')['closure_hours'].mean().dropna().sort_values()
best_state = state_avg.index[0] if len(state_avg) > 0 else None
result = json.dumps(best_state)
print('__RESULT__:')
print(result)"""

